test('WMET-001-Verify Resource Unit Update', async ({ page }) => {
    await page.setViewportSize({ width: 1920, height: 1080 });
    await page.goto('http://localhost:5004/workmapping');
    test.info().annotations.push({ type: 'Sample link', description: 'http://localhost:5004/workmapping' });
    await page.waitForTimeout(2000);
    //Click the 6 th record that has Fixed Duration
    await page.locator("(//td[contains(@class,'e-rowcell')])[42]").click();
    await page.waitForTimeout(500);
    //Click the Edit button on the toolbar
    await page.locator("(//span[text()='Edit'])[1]").click();
    await page.waitForTimeout(500);
    //Navigate to resources to open the dialog tab
    await page.locator("(//div[contains(@class,'e-tab-text')])[2]").click();
    await page.waitForTimeout(500);
    //Click the save button
    await page.locator("(//button[text()='Save'])[1]").click();
    await page.waitForTimeout(500);
    //Click the 6 th record that has Fixed Duration
    await page.locator("(//td[contains(@class,'e-rowcell')])[42]").click();
    await page.waitForTimeout(500);
    //Click the Edit button on the toolbar
    await page.locator("(//span[text()='Edit'])[1]").click();
    await page.waitForTimeout(500);
    //Navigate to resources to open the dialog tab
    await page.locator("(//div[contains(@class,'e-tab-text')])[2]").click();
    await page.waitForTimeout(2000);
    //Screenshot validation-The task details when the resources are opened is 100%
    expect(await page.locator('.e-gantt').screenshot()).toMatchSnapshot({ maxDiffPixels: 100 });
});

