test('WMET-006-Edit Duration and Verify Work', async ({ page }) => {
    await page.setViewportSize({ width: 1920, height: 1080 });
    await page.goto('http://localhost:5004/workmapping');
    test.info().annotations.push({ type: 'Sample link', description: 'http://localhost:5004/workmapping' });
    await page.waitForTimeout(2000);
    //Double click the 6 th task 
    await page.locator("(//div[contains(@class,'e-gantt-child')])[7]").dblclick();
    await page.waitForTimeout(1000);
    //Click to select the duration
    await page.locator("(//input[contains(@class,'e-control')])[4]").click();
    await page.waitForTimeout(500);
    await page.keyboard.press('Control+A');
    await page.keyboard.press('Backspace');
    await page.keyboard.type('5 days');
    //Click the save button on the toolbar
    await page.locator("(//button[text()='Save'])[1]").click();
    await page.waitForTimeout(2000);
    await page.locator('(//td[contains(@class, "e-rowcell")])[1]').click();
    await page.waitForTimeout(200);
    //Screenshot validation-The new day added is presented visually on the taskbar on the chart side.
    expect.soft(await page.locator('.e-gantt').screenshot()).toMatchSnapshot({ maxDiffPixels: 100 });
});

