test('WMET-386', async ({ page }) => {
    await page.setViewportSize({ width: 1920, height: 1080 });
    await page.goto('http://localhost:5004/workmapping');
    test.info().annotations.push({ type: 'Sample link', description: 'http://localhost:5004/workmapping' });
    await page.waitForTimeout(2000);
    //Select from Auto to Manual mode
    await page.locator("(//span[contains(@class,'e-input-group')])[24]").click();
    await page.waitForTimeout(500);
    //select Manual 
    await page.locator("(//li[text()='Manual'])[1]").click();
    await page.waitForTimeout(1000)
    //Select Task Type
    await page.locator("(//span[contains(@class,'e-input-group')])[29]").click();
    await page.waitForTimeout(500);
    //select Update Assignment
    await page.locator("(//li[text()='UpdateAssignment'])[1]").click();
    await page.waitForTimeout(500);
    //Click update button
    await page.locator("(//button[text()='Click'])[1]").click();
    await page.waitForTimeout(1000);
    // Verify that the task assignment is updated to "Davolio Fuller" in the Gantt chart
    const ganttChart = page.locator('.e-gantt');
    await expect(ganttChart).toContainText("Davolio Fuller");
    // Count occurrences of Davolio Fuller to confirm assignment is added
    const davolioCount = await page.locator('.e-gantt').locator('text=Davolio Fuller').count();
    expect(davolioCount).toBeGreaterThan(0);
    //Select record 
    await page.locator("(//span[contains(@class,'e-input-group')])[27]").click();
    await page.waitForTimeout(500);
    //select FixedUnit 
    await page.locator("(//li[text()='FixedUnit'])[1]").click();
    await page.waitForTimeout(1000)
    //select startdate
    await page.locator("(//td[contains(@class,'e-rowcell')])[23]").click();
    await page.waitForTimeout(1000);
    // Verify the start date of the 3rd task is 3/29/2022 
    const startDateCell = page.locator("(//td[contains(@class,'e-rowcell')])[23]");
    await expect(startDateCell).toContainText("3/29/2022");
    // Verify the end date is 4/3/2022
    await expect(ganttChart).toContainText("4/3/2022");
    //Click the taskbars
    await page.locator("(//div[contains(@class,'e-gantt-child-taskbar')])[2]").hover({ force: true });
    await page.waitForTimeout(2000);
    // Verify Gantt chart is visible and Davolio Fuller assignment is still visible
    await expect(ganttChart).toBeVisible();
    await expect(ganttChart).toContainText("Davolio Fuller");
    expect.soft(await page.locator('.e-gantt').screenshot()).toMatchSnapshot({ maxDiffPixels: 100 });
});

